"""
Parameterized generator for GH845_clinica_1563.

Source PR:    https://github.com/aramis-lab/clinica/pull/1563
Source Issue: https://github.com/aramis-lab/clinica/issues/1560

Seed varies: renames 'acq_time' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH845_clinica_1563'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH845_clinica_1563'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('acq_time', 'acq_time' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH845_clinica_1563',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'aramis-lab/clinica',
                "pr_number": 1563,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/aramis-lab/clinica/pull/1563",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'clinica/converters/ixi_to_bids/_utils.py': 'import json\nimport re\nimport shutil\nfrom enum import Enum\nfrom pathlib import Path\nfrom typing import List, Optional, Union\n\nimport nibabel as nib\nimport pandas as pd\nfrom nilearn.image import concat_imgs\n\nfrom clinica.converters.study_models import StudyName, bids_id_factory\nfrom clinica.utils.stream import cprint, log_and_raise\n\n__all__ = [\n    "read_clinical_data",\n    "define_participants",\n    "write_subject_data",\n    "write_sessions",\n    "write_scans",\n    "write_participants",\n    "check_modalities",\n    "write_dwi_b_values",\n]\n\n\ndef write_dwi_b_values(bids_dir: Path) -> None:\n    """Writes DWI bval and bvec files at the root of the BIDS directory"""\n    b_folder = Path(__file__).parents[0] / "dwi_b_files"\n    shutil.copy(b_folder / "bvals.txt", bids_dir / "dwi.bval")\n    shutil.copy(b_folder / "bvecs.txt", bids_dir / "dwi.bvec")\n\n\ndef _get_subjects_list_from_data(data_directory: Path) -> List[str]:\n    return list(\n        dict.fromkeys(\n            re.match(r"IXI\\d{3}", path.name).group(0)\n            for path in data_directory.rglob(pattern="IXI*.nii.gz")\n            if re.match(r"IXI\\d{3}", path.name)\n        )\n    )\n\n\ndef define_participants(\n    data_directory: Path,\n    subjs_list_path: Optional[Path] = None,\n) -> List[str]:\n    """\n    Defines the actual list of participants based on the (provided) subjects list filtered\n    using existing data.\n\n    Parameters\n    ----------\n    data_directory : Path to the raw data directory.\n    subjs_list_path : [Optional] Path to a text file containing a list of specific subjects to extract.\n\n    Returns\n    -------\n    The list of ids that were either present in the data directory or asked for with a specific text file, provided\n    associated images actually exists.\n\n    """\n\n    from .._utils import get_subjects_list_from_file\n\n    list_from_data = _get_subjects_list_from_data(data_directory)\n    if subjs_list_path is None:\n        return sorted(list_from_data)\n    cprint("Loading a subjects list provided by the user...")\n    list_from_file = get_subjects_list_from_file(subjs_list_path)\n    list_filtered = [subject for subject in list_from_file if subject in list_from_data]\n    invalid_subjects = list(set(list_from_file) - set(list_filtered))\n    if invalid_subjects:\n        cprint(\n            f"The subjects : {\' , \'.join(invalid_subjects)} do not have any associated data inside the directory {data_directory}"\n            f" and can not be converted."\n        )\n    return sorted(list_filtered)\n\n\ndef _rename_clinical_data_to_bids(column: str) -> str:\n    if column == "SEX_ID (1=m, 2=f)":\n        return "sex"\n    if column == "ETHNIC_ID":\n        return "ethnicity"\n    if column == "MARITAL_ID":\n        return "marital status"\n    if column == "OCCUPATION_ID":\n        return "occupation"\n    if column == "QUALIFICATION_ID":\n        return "qualification"\n    if column == "IXI_ID":\n        return "source_id"\n    if column == "DOB":\n        return "date of birth"\n    if column == "STUDY_DATE":\n        return "acq_time"\n    else:\n        return column.lower()\n\n\ndef _get_sex_mapping() -> pd.DataFrame:\n    return pd.DataFrame({"SEX": ["male", "female"]}, index=[1, 2])["SEX"]\n\n\nclass ClinicalDataMapping(str, Enum):\n    ETHNIC = "Ethnicity"\n    MARITAL = "Marital Status"\n    OCCUPATION = "Occupation"\n    QUALIFICATION = "Qualification"\n\n\ndef _get_mapping(clinical_data_path: Path, map: ClinicalDataMapping) -> pd.Series:\n    try:\n        return pd.read_excel(\n            clinical_data_path / "IXI.xls", sheet_name=map.value\n        ).set_index("ID")[map.name]\n    except FileNotFoundError:\n        log_and_raise(\n            f"Clinical data stored in the folder {clinical_data_path} is expected to be an excel file named \'IXI.xls\'. "\n            f"In case the file downloaded from the IXI website changed format, please do not hesitate to report to us !",\n            FileNotFoundError,\n        )\n    except (ValueError, KeyError):\n        log_and_raise(\n            f"{map.value} mapping is expected to be contained in a sheet called {map.value} coming from the clinical data excel. "\n            f"Possibilities are supposed to be described in a {map.name} column associated to keys from the \'ID\' column. "\n            f"In case the file downloaded from the IXI website changed format, please do not hesitate to report to us !",\n            ValueError,\n        )\n\n\ndef _padding_source_id(source_id: Union[str, int]) -> str:\n    if len(str(source_id)) > 3:\n        log_and_raise(\n            f"The source id {source_id} has more than 3 digits while IXI"\n            f"source ids are expected to be between 1 and 3 digits.",\n            ValueError,\n        )\n    return f"IXI{\'0\'* (3 - len(str(source_id))) + str(source_id)}"\n\n\ndef read_clinical_data(clinical_data_path: Path) -> pd.DataFrame:\n    """\n    Reads and formats IXI clinical data.\n\n    Parameters\n    ----------\n    clinical_data_path : Path to the directory where the clinical data .xls is stored.\n\n    Returns\n    -------\n    A dataframe containing the clinical data, with some modifications: padded study id and added session id.\n\n    """\n    try:\n        clinical_data = pd.read_excel(clinical_data_path / "IXI.xls")\n    except FileNotFoundError:\n        log_and_raise(\n            f"Clinical data stored in the folder {clinical_data_path} is expected to be an excel file named \'IXI.xls\'. "\n            f"In case the file downloaded from the IXI website changed format, please do not hesitate to report to us !",\n            FileNotFoundError,\n        )\n    else:\n        if "DATE_AVAILABLE" in clinical_data.columns:\n            clinical_data.drop("DATE_AVAILABLE", axis=1, inplace=True)\n        clinical_data["SEX_ID (1=m, 2=f)"] = clinical_data["SEX_ID (1=m, 2=f)"].map(\n            _get_sex_mapping()\n        )\n        for mapping in ClinicalDataMapping:\n            clinical_data[f"{mapping.name}_ID"] = clinical_data[\n                f"{mapping.name}_ID"\n            ].map(_get_mapping(clinical_data_path, mapping))\n\n        clinical_data["IXI_ID"] = clinical_data.IXI_ID.apply(\n            lambda x: _padding_source_id(x)\n        )\n        clinical_data.rename(\n            lambda x: _rename_clinical_data_to_bids(x), axis=1, inplace=True\n        )\n        clinical_data.fillna("n/a", inplace=True)\n        clinical_data["session_id"] = "ses-M000"\n        return clinical_data\n\n\ndef _rename_modalities(input_mod: str) -> str:\n    if input_mod == "T1":\n        return "T1w"\n    if input_mod == "T2":\n        return "T2w"\n    if input_mod == "MRA":\n        return "angio"\n    if input_mod == "PD":\n        return "PDw"\n    if input_mod == "DTI":\n        return "dti"\n    raise ValueError(f"The modality {input_mod} is not recognized in the IXI dataset.")\n\n\ndef _define_magnetic_field(hospital: str) -> str:\n    if hospital in ("Guys", "IOP"):\n        return "1.5"\n    if hospital == "HH":\n        return "3"\n    raise ValueError(f"The hospital {hospital} was not recognized.")\n\n\ndef _get_img_data(data_directory: Path) -> pd.DataFrame:\n    """Finds paths for all images that are not DTI data and processes the info contained in their names"""\n    df = pd.DataFrame(\n        {\n            "img_path": [\n                path\n                for path in data_directory.rglob(pattern="IXI*.nii.gz")\n                if re.search(r"IXI\\d{3}(-\\w*){3}.nii.gz$", str(path))\n            ]\n        }\n    )\n    df = (\n        df.assign(img_name=lambda df: df.img_path.apply(lambda x: x.name))\n        .assign(img_name_no_ext=lambda df: df.img_name.apply(lambda x: x.split(".")[0]))\n        .assign(subject=lambda df: df.img_name_no_ext.apply(lambda x: x.split("-")[0]))\n        .assign(\n            participant_id=lambda df: df.subject.apply(\n                lambda x: bids_id_factory(StudyName.IXI).from_original_study_id(x)\n            )\n        )\n        .assign(hospital=lambda df: df.img_name_no_ext.apply(lambda x: x.split("-")[1]))\n        .assign(\n            modality=lambda df: df.img_name_no_ext.apply(\n                lambda x: _rename_modalities(x.split("-")[3])\n            )\n        )\n        .assign(field=lambda df: df.hospital.apply(lambda x: _define_magnetic_field(x)))\n        .assign(session="ses-M000")\n    )\n    return df\n\n\ndef _get_bids_filename_from_image_data(img: pd.Series) -> str:\n    return f"{img[\'participant_id\']}_{img[\'session\']}_{img[\'modality\']}"\n\n\ndef write_subject_data(bids_dir: Path, participant: str, path_to_dataset: Path) -> None:\n    """\n    Writes the data of the IXI subject in the BIDS directory following BIDS specifications.\n\n    Parameters\n    ----------\n    bids_dir : Path to the output BIDS directory.\n    participant : Current converted subject study id (str).\n    path_to_dataset : Path to the raw dataset directory.\n    """\n    data_df = _get_img_data(path_to_dataset)\n    _write_subject_no_dti(data_df[data_df["subject"] == participant], bids_dir)\n    _write_subject_dti_if_exists(bids_dir, participant, path_to_dataset)\n\n\ndef _write_json_image(writing_path: Path, hospital: str, field: str) -> None:\n    """\n    Writes a json associated to one IXI image.\n\n    Parameters\n    ----------\n    writing_path : Path indicating under what name to write the json.\n    hospital : identifier for the hospital responsible for the acquisition, determined from the image filename.\n    field :  magnetic field used for the acquisition of the image, determined from the hospital.\n    """\n    with open(writing_path, "w") as f:\n        json.dump(\n            {\n                "InstitutionName": hospital,\n                "MagneticFieldStrength (T)": field,\n            },\n            f,\n            indent=4,\n        )\n\n\ndef _write_subject_no_dti(subject_df: pd.DataFrame, bids_path: Path) -> None:\n    """Copies all subject data but DTI"""\n    for _, row in subject_df.iterrows():\n        cprint(\n            f"Converting modality {row[\'modality\']} for subject {row[\'subject\']}.",\n            lvl="debug",\n        )\n        filename = _get_bids_filename_from_image_data(row)\n        data_path = bids_path / row["participant_id"] / row["session"] / "anat"\n        data_path.mkdir(parents=True, exist_ok=True)\n        shutil.copy2(row["img_path"], f"{data_path}/{filename}.nii.gz")\n        _write_json_image(\n            (data_path / filename).with_suffix(".json"), row["hospital"], row["field"]\n        )\n\n\ndef _write_subject_dti_if_exists(\n    bids_path: Path, subject: str, data_directory: Path\n) -> None:\n    """Processes DTI data if found for a subject"""\n    if dti_paths := _find_subject_dti_data(data_directory, subject):\n        cprint(f"Converting modality DTI for subject {subject}.", lvl="debug")\n        dti_to_save = _merge_dti(dti_paths)\n        bids_id = bids_id_factory(StudyName.IXI).from_original_study_id(subject)\n        data_path = bids_path / bids_id / "ses-M000" / "dwi"\n        data_path.mkdir(parents=True, exist_ok=True)\n        filename = Path(f"{bids_id}_ses-M000_dwi")\n        dti_to_save.to_filename(data_path / filename.with_suffix(".nii.gz"))\n        hospital = dti_paths[0].name.split("-")[1]\n        _write_json_image(\n            data_path / filename.with_suffix(".json"),\n            hospital,\n            _define_magnetic_field(hospital),\n        )\n\n\ndef _find_subject_dti_data(data_directory: Path, subject: str) -> List[Path]:\n    pattern = subject + r"(-\\w*){2}-DTI(-(0[1-9]|[1-9][0-9])){1}.nii.gz$"\n    return [\n        path\n        for path in data_directory.rglob(pattern="IXI*.nii.gz")\n        if re.search(pattern, str(path))\n    ]\n\n\ndef _merge_dti(dti_images: List[Path]) -> nib.Nifti1Image:\n    return concat_imgs([nib.load(img) for img in dti_images])\n\n\ndef write_scans(bids_dir: Path, participant: str) -> None:\n    """\n    Write the scans.tsv for the only session (ses-M000) of a IXI subject.\n\n    Parameters\n    ----------\n    bids_dir : Path to the output BIDS directory.\n    participant : Current converted subject study id (str).\n    """\n    bids_id = bids_id_factory(StudyName.IXI).from_original_study_id(participant)\n    to_write = pd.DataFrame(\n        {\n            "filename": [\n                f"{path.parent.name}/{path.name}"\n                for path in (bids_dir / bids_id).rglob(f"{bids_id}*.nii.gz")\n            ]\n        }\n    )\n    to_write.to_csv(\n        bids_dir / bids_id / "ses-M000" / f"{bids_id}_ses-M000_scans.tsv",\n        sep="\\t",\n        index=False,\n    )\n\n\ndef write_sessions(\n    bids_dir: Path, clinical_data: pd.DataFrame, participant: str\n) -> None:\n    """\n    Writes the sessions.tsv for a IXI subject.\n\n    Parameters\n    ----------\n    bids_dir : Path to the output BIDS directory.\n    clinical_data : Dataframe containing the formatted clinical data of the IXI study.\n    participant : Current converted subject study id (str).\n    """\n    to_write = clinical_data[clinical_data["source_id"] == participant][\n        ["source_id", "session_id", "acq_time"]\n    ]\n    if to_write.empty:\n        to_write.loc[0, "source_id"] = participant\n        to_write.fillna("n/a", inplace=True)\n    bids_id = bids_id_factory(StudyName.IXI).from_original_study_id(participant)\n    to_write.to_csv(\n        bids_dir / bids_id / f"{bids_id}_sessions.tsv", sep="\\t", index=False\n    )\n\n\ndef write_participants(\n    bids_dir: Path, clinical_data: pd.DataFrame, participants: List[str]\n) -> None:\n    """\n    Write the participants.tsv at the root of the BIDS directory.\n\n    Parameters\n    ----------\n    bids_dir : Path to the output BIDS directory.\n    clinical_data : Dataframe containing the formatted clinical data of the IXI study.\n    participants : List of converted subjects study source ids.\n    """\n    clinical_data.set_index("source_id", inplace=True, drop=False)\n    clinical_data = clinical_data.assign(\n        participant_id=clinical_data.source_id.apply(\n            lambda x: bids_id_factory(StudyName.IXI).from_original_study_id(x)\n        )\n    )\n    for participant in participants:\n        if participant not in clinical_data.index:\n            clinical_data.loc[participant] = "n/a"\n            clinical_data.loc[participant, "source_id"] = participant\n    if not bids_dir.exists():\n        bids_dir.mkdir()\n    clinical_data.loc[participants].drop(["acq_time", "session_id"], axis=1).to_csv(\n        bids_dir / "participants.tsv", sep="\\t", index=False, na_rep="n/a"\n    )\n    clinical_data.reset_index(drop=True, inplace=True)\n\n\ndef _identify_expected_modalities(data_directory: Path) -> List[str]:\n    return [\n        p.name.split("-")[1]\n        for p in data_directory.iterdir()\n        if p.is_dir() and "IXI-" in str(p)\n    ]\n\n\ndef check_modalities(data_directory: Path, participants: List[str]) -> None:\n    """\n    Verify what modality folders are available in the given data directory and checks if some are missing per participant\n\n    Parameters\n    ----------\n    data_directory : Path to raw dataset.\n    participants : List of the subject ids of all participants\n\n    """\n    expected_modalities = sorted(_identify_expected_modalities(data_directory))\n    message = (\n        f"Modalities : {\' , \'.join(_rename_modalities(mod) for mod in expected_modalities)}"\n        f" were identified inside {data_directory} for conversion.\\n"\n    )\n    participants_missing_mod = dict()\n    for participant in participants:\n        missing_mods = []\n        for mod in expected_modalities:\n            if not list(data_directory.rglob(f"{participant}*{mod}*.nii.gz")):\n                missing_mods += [_rename_modalities(mod)]\n        if missing_mods:\n            participants_missing_mod[participant] = missing_mods\n    if participants_missing_mod:\n        message += f"Some subjects do not have data for the following modalities :\\n"\n        for sub, mod in participants_missing_mod.items():\n            message += f"{sub} : {\' , \'.join(mod)}\\n"\n\n    cprint(message)\n',
            'test/unittests/converters/test_ixi_to_bids_utils.py': 'import json\nfrom pathlib import Path\nfrom unittest.mock import patch\n\nimport nibabel\nimport numpy as np\nimport pandas as pd\nimport pytest\nfrom pandas.testing import assert_frame_equal, assert_series_equal\n\n\ndef test_write_dwi_b_values(tmp_path):\n    from clinica.converters.ixi_to_bids._utils import write_dwi_b_values\n\n    write_dwi_b_values(tmp_path)\n    bvec_files = list(tmp_path.rglob("*.bvec"))\n    bval_files = list(tmp_path.rglob("*.bval"))\n\n    assert len(bvec_files) == 1 and bvec_files[0].name == "dwi.bvec"\n    assert len(bval_files) == 1 and bval_files[0].name == "dwi.bval"\n\n\ndef test_get_subjects_list_from_data(tmp_path):\n    from clinica.converters.ixi_to_bids._utils import _get_subjects_list_from_data\n\n    for filename in ("IXI1", "IXI123", "IXIaaa", "foo"):\n        (tmp_path / f"{filename}_T1w.nii.gz").touch()\n\n    assert _get_subjects_list_from_data(tmp_path) == ["IXI123"]\n\n\ndef test_define_participants_filter(tmp_path):\n    from clinica.converters.ixi_to_bids._utils import define_participants\n\n    for filename in ("IXI001", "IXI002", "IXI003", "IXI004"):\n        (tmp_path / f"{filename}_T1w.nii.gz").touch()\n    with open(tmp_path / "subjects.txt", "w") as f:\n        f.write("IXI001\\nIXI006")\n\n    assert define_participants(\n        data_directory=tmp_path, subjs_list_path=tmp_path / "subjects.txt"\n    ) == ["IXI001"]\n\n\ndef test_define_participants_optional(tmp_path):\n    from clinica.converters.ixi_to_bids._utils import define_participants\n\n    for filename in ("IXI001", "IXI002"):\n        (tmp_path / f"{filename}_T1w.nii.gz").touch()\n\n    assert define_participants(data_directory=tmp_path) == ["IXI001", "IXI002"]\n\n\n@pytest.mark.parametrize(\n    "input_str, expected",\n    [\n        ("T1", "T1w"),\n        ("T2", "T2w"),\n        ("MRA", "angio"),\n        ("PD", "PDw"),\n        ("DTI", "dti"),\n    ],\n)\ndef test_rename_ixi_modalities_success(input_str: str, expected: str):\n    from clinica.converters.ixi_to_bids._utils import _rename_modalities\n\n    assert _rename_modalities(input_str) == expected\n\n\n@pytest.mark.parametrize("input_str", ["t1", "foo", "T1w"])\ndef test_rename_ixi_modalities_error(input_str: str):\n    from clinica.converters.ixi_to_bids._utils import _rename_modalities\n\n    with pytest.raises(\n        ValueError,\n        match=f"The modality {input_str} is not recognized in the IXI dataset.",\n    ):\n        _rename_modalities(input_str)\n\n\n@pytest.mark.parametrize(\n    "input_str, expected",\n    [\n        ("SEX_ID (1=m, 2=f)", "sex"),\n        ("ETHNIC_ID", "ethnicity"),\n        ("MARITAL_ID", "marital status"),\n        ("OCCUPATION_ID", "occupation"),\n        ("QUALIFICATION_ID", "qualification"),\n        ("IXI_ID", "source_id"),\n        ("DOB", "date of birth"),\n        ("STUDY_DATE", "acq_time"),\n        ("FOO", "foo"),\n    ],\n)\ndef test_rename_clinical_data_to_bids(input_str: str, expected: str):\n    from clinica.converters.ixi_to_bids._utils import _rename_clinical_data_to_bids\n\n    assert _rename_clinical_data_to_bids(input_str) == expected\n\n\n@pytest.mark.parametrize(\n    "input, expected",\n    [\n        ("1", "IXI001"),\n        ("12", "IXI012"),\n        ("123", "IXI123"),\n        (1, "IXI001"),\n    ],\n)\ndef test_padding_source_id_success(input: str, expected: str):\n    from clinica.converters.ixi_to_bids._utils import _padding_source_id\n\n    assert _padding_source_id(input) == expected\n\n\ndef test_padding_source_id_error():\n    from clinica.converters.ixi_to_bids._utils import _padding_source_id\n\n    with pytest.raises(\n        ValueError,\n        match=(\n            f"The source id 1234 has more than 3 digits while IXI"\n            f"source ids are expected to be between 1 and 3 digits."\n        ),\n    ):\n        _padding_source_id("1234")\n\n\n@pytest.mark.parametrize("input", ["IXI_name.xls", "IXI_format.csv"])\ndef test_read_clinical_data_error(tmp_path, input: str):\n    from clinica.converters.ixi_to_bids._utils import read_clinical_data\n\n    (tmp_path / input).touch()\n    with pytest.raises(\n        FileNotFoundError,\n        match=(\n            f"Clinical data stored in the folder {tmp_path} is expected to be an excel file named \'IXI.xls\'. "\n            f"In case the file downloaded from the IXI website changed format, please do not hesitate to report to us !"\n        ),\n    ):\n        read_clinical_data(tmp_path)\n\n\ndef clinical_data_builder(tmp_path: Path) -> None:\n    marital = pd.DataFrame(\n        {\n            "ID": [1, 2, 4, 3, 5],\n            "MARITAL": [\n                "Single",\n                "Married",\n                "Divorced or Separated",\n                "Cohabiting",\n                "Widowed",\n            ],\n        }\n    )\n    ethnic = pd.DataFrame(\n        {\n            "ID": [1, 4, 3, 5, 6],\n            "ETHNIC": [\n                "White",\n                "Black or BlackBritish",\n                "Asian or Asian British",\n                "Chinese",\n                "Other",\n            ],\n        }\n    )\n    occup = pd.DataFrame(\n        {\n            "ID": [1, 2, 3, 4, 5, 6, 7, 8],\n            "OCCUPATION": [\n                "Go out to full time employment",\n                "Go out to part time employment (<25hrs)",\n                "Study at college or university",\n                "Full-time housework",\n                "Retired",\n                "Unemployed",\n                "Work for pay at home",\n                "Other",\n            ],\n        }\n    )\n    qualif = pd.DataFrame(\n        {\n            "ID": [1, 2, 3, 4, 5],\n            "QUALIFICATION": [\n                "No qualifications",\n                "O - levels, GCSEs, or CSEs",\n                "A - levels",\n                "Further education e.g.City & Guilds / NVQs",\n                "University or Polytechnic degree",\n            ],\n        }\n    )\n    subject = pd.DataFrame(\n        {\n            "IXI_ID": ["1"],\n            "STUDY_DATE": ["2024-08-23"],\n            "SEX_ID (1=m, 2=f)": [2],\n            "ETHNIC_ID": [6],\n            "MARITAL_ID": [1],\n            "OCCUPATION_ID": [8],\n            "QUALIFICATION_ID": [3],\n            "DOB": ["2000-01-01"],\n            "WEIGHT": [80],\n        }\n    )\n    with pd.ExcelWriter(tmp_path / "IXI.xls") as writer:\n        subject.to_excel(writer, index=False)\n        qualif.to_excel(writer, sheet_name="Qualification", index=False)\n        occup.to_excel(writer, sheet_name="Occupation", index=False)\n        ethnic.to_excel(writer, sheet_name="Ethnicity", index=False)\n        marital.to_excel(writer, sheet_name="Marital Status", index=False)\n\n\ndef test_read_clinical_data_success(tmp_path):\n    from clinica.converters.ixi_to_bids._utils import read_clinical_data\n\n    clinical_data_builder(tmp_path)\n\n    assert (\n        read_clinical_data(tmp_path)\n        .eq(formatted_clinical_data_builder().drop("participant_id", axis=1))\n        .all()\n        .all()\n    )\n\n\ndef test_merge_dti(tmp_path):\n    from clinica.converters.ixi_to_bids._utils import _merge_dti\n\n    im1 = nibabel.Nifti1Image(\n        np.empty(shape=(256, 156, 256), dtype=np.float64), np.eye(4)\n    )\n    im1.to_filename(tmp_path / "im1.nii.gz")\n    im2 = nibabel.Nifti1Image(\n        np.empty(shape=(256, 156, 256), dtype=np.float64), np.eye(4)\n    )\n    im2.to_filename(tmp_path / "im2.nii.gz")\n    merged = _merge_dti([tmp_path / "im1.nii.gz", tmp_path / "im2.nii.gz"])\n\n    assert type(merged) == nibabel.Nifti1Image\n    assert merged.shape[-1] == 2\n\n\ndef test_write_dti_success(tmp_path):\n    from clinica.converters.ixi_to_bids._utils import _write_subject_dti_if_exists\n\n    im1 = nibabel.Nifti1Image(\n        np.empty(shape=(256, 156, 256), dtype=np.float64), np.eye(4)\n    )\n    im1.to_filename(tmp_path / "IXI001-Guys-1234-DTI-00.nii.gz")\n    im2 = nibabel.Nifti1Image(\n        np.empty(shape=(256, 156, 256), dtype=np.float64), np.eye(4)\n    )\n    im2.to_filename(tmp_path / "IXI001-Guys-1234-DTI-01.nii.gz")\n\n    _write_subject_dti_if_exists(\n        bids_path=tmp_path, subject="IXI001", data_directory=tmp_path\n    )\n    dti_image = list(tmp_path.rglob(pattern="*dwi.nii.gz"))\n    dti_json = list(tmp_path.rglob(pattern="*dwi.json"))\n\n    assert (\n        len(dti_image) == 1\n        and dti_image[0]\n        == tmp_path\n        / "sub-IXI001"\n        / "ses-M000"\n        / "dwi"\n        / "sub-IXI001_ses-M000_dwi.nii.gz"\n    )\n    assert (\n        len(dti_json) == 1\n        and dti_json[0]\n        == tmp_path / "sub-IXI001" / "ses-M000" / "dwi" / "sub-IXI001_ses-M000_dwi.json"\n    )\n\n\ndef test_write_dti_empty(tmp_path):\n    from clinica.converters.ixi_to_bids._utils import _write_subject_dti_if_exists\n\n    _write_subject_dti_if_exists(\n        bids_path=tmp_path, subject="IXI001", data_directory=tmp_path\n    )\n    dti_files = list(tmp_path.rglob(pattern="*dwi.nii.gz"))\n\n    assert not dti_files\n\n\n@pytest.mark.parametrize(\n    "input_str, expected",\n    [\n        ("Guys", "1.5"),\n        ("IOP", "1.5"),\n        ("HH", "3"),\n    ],\n)\ndef test_define_magnetic_field_success(input_str: str, expected: str):\n    from clinica.converters.ixi_to_bids._utils import _define_magnetic_field\n\n    assert _define_magnetic_field(input_str) == expected\n\n\ndef test_define_magnetic_field_error():\n    from clinica.converters.ixi_to_bids._utils import _define_magnetic_field\n\n    with pytest.raises(\n        ValueError,\n        match=f"The hospital foo was not recognized.",\n    ):\n        _define_magnetic_field("foo")\n\n\ndef image_dataframe_builder(tmp_path: Path) -> pd.DataFrame:\n    tmp_image = tmp_path / "IXI001-Guys-1234-T1.nii.gz"\n    tmp_image.touch()\n    (tmp_path / "IXI001-Guys-1234-T1").touch()\n    (tmp_path / "IXI001-Guys-T1.nii.gz").touch()\n    (tmp_path / "IXI001-Guys-1234-T1-00.nii.gz").touch()\n\n    return pd.DataFrame(\n        {\n            "img_path": [tmp_image],\n            "img_name": ["IXI001-Guys-1234-T1.nii.gz"],\n            "img_name_no_ext": ["IXI001-Guys-1234-T1"],\n            "subject": ["IXI001"],\n            "participant_id": ["sub-IXI001"],\n            "hospital": ["Guys"],\n            "modality": ["T1w"],\n            "field": ["1.5"],\n            "session": ["ses-M000"],\n        }\n    )\n\n\ndef test_get_image_data(tmp_path):\n    from clinica.converters.ixi_to_bids._utils import _get_img_data\n\n    input = image_dataframe_builder(tmp_path)\n\n    assert assert_frame_equal(_get_img_data(tmp_path), input) is None\n\n\ndef test_get_bids_filename_from_image_data(tmp_path):\n    from clinica.converters.ixi_to_bids._utils import _get_bids_filename_from_image_data\n\n    input = image_dataframe_builder(tmp_path)\n\n    assert _get_bids_filename_from_image_data(input.loc[0]) == "sub-IXI001_ses-M000_T1w"\n\n\ndef test_get_marital_mapping_success(tmp_path):\n    from clinica.converters.ixi_to_bids._utils import ClinicalDataMapping, _get_mapping\n\n    marital = pd.DataFrame(\n        {\n            "ID": [1, 2, 4, 3, 5],\n            "MARITAL": [\n                "Single",\n                "Married",\n                "Divorced or Separated",\n                "Cohabiting",\n                "Widowed",\n            ],\n        }\n    )\n    marital.to_excel(excel_writer=tmp_path / "IXI.xls", sheet_name="Marital Status")\n\n    assert (\n        assert_series_equal(\n            _get_mapping(tmp_path, ClinicalDataMapping.MARITAL),\n            marital.set_index("ID")["MARITAL"],\n        )\n        is None\n    )\n\n\ndef test_get_ethnic_mapping_success(tmp_path):\n    from clinica.converters.ixi_to_bids._utils import ClinicalDataMapping, _get_mapping\n\n    ethnic = pd.DataFrame(\n        {\n            "ID": [1, 4, 3, 5, 6],\n            "ETHNIC": [\n                "White",\n                "Black or BlackBritish",\n                "Asian or Asian British",\n                "Chinese",\n                "Other",\n            ],\n        }\n    )\n    ethnic.to_excel(excel_writer=tmp_path / "IXI.xls", sheet_name="Ethnicity")\n\n    assert (\n        assert_series_equal(\n            _get_mapping(tmp_path, ClinicalDataMapping.ETHNIC),\n            ethnic.set_index("ID")["ETHNIC"],\n        )\n        is None\n    )\n\n\ndef test_get_occupation_mapping_success(tmp_path):\n    from clinica.converters.ixi_to_bids._utils import ClinicalDataMapping, _get_mapping\n\n    occup = pd.DataFrame(\n        {\n            "ID": [1, 2, 3, 4, 5, 6, 7, 8],\n            "OCCUPATION": [\n                "Go out to full time employment",\n                "Go out to part time employment (<25hrs)",\n                "Study at college or university",\n                "Full-time housework",\n                "Retired",\n                "Unemployed",\n                "Work for pay at home",\n                "Other",\n            ],\n        }\n    )\n    occup.to_excel(excel_writer=tmp_path / "IXI.xls", sheet_name="Occupation")\n\n    assert (\n        assert_series_equal(\n            _get_mapping(tmp_path, ClinicalDataMapping.OCCUPATION),\n            occup.set_index("ID")["OCCUPATION"],\n        )\n        is None\n    )\n\n\ndef test_get_qualification_mapping_success(tmp_path):\n    from clinica.converters.ixi_to_bids._utils import ClinicalDataMapping, _get_mapping\n\n    qualif = pd.DataFrame(\n        {\n            "ID": [1, 2, 3, 4, 5],\n            "QUALIFICATION": [\n                "No qualifications",\n                "O - levels, GCSEs, or CSEs",\n                "A - levels",\n                "Further education e.g.City & Guilds / NVQs",\n                "University or Polytechnic degree",\n            ],\n        }\n    )\n    qualif.to_excel(excel_writer=tmp_path / "IXI.xls", sheet_name="Qualification")\n\n    assert (\n        assert_series_equal(\n            _get_mapping(tmp_path, ClinicalDataMapping.QUALIFICATION),\n            qualif.set_index("ID")["QUALIFICATION"],\n        )\n        is None\n    )\n\n\ndef test_get_mapping_fileerror(tmp_path):\n    from clinica.converters.ixi_to_bids._utils import ClinicalDataMapping, _get_mapping\n\n    qualif = pd.DataFrame(\n        {\n            "ID": [1, 2, 3, 4, 5],\n            "QUALIFICATION": [\n                "No qualifications",\n                "O - levels, GCSEs, or CSEs",\n                "A - levels",\n                "Further education e.g.City & Guilds / NVQs",\n                "University or Polytechnic degree",\n            ],\n        }\n    )\n    qualif.to_excel(excel_writer=tmp_path / "IXI2.xls", sheet_name="Qualification")\n\n    with pytest.raises(\n        FileNotFoundError,\n        match=(\n            f"Clinical data stored in the folder {tmp_path} is expected to be an excel file named \'IXI.xls\'. "\n            f"In case the file downloaded from the IXI website changed format, please do not hesitate to report to us !"\n        ),\n    ):\n        _get_mapping(tmp_path, ClinicalDataMapping.QUALIFICATION)\n\n\ndef test_get_mapping_keyerror(tmp_path):\n    from clinica.converters.ixi_to_bids._utils import ClinicalDataMapping, _get_mapping\n\n    qualif = pd.DataFrame(\n        {\n            "ID": [1, 2, 3, 4, 5],\n            "QUALIFICATION": [\n                "No qualifications",\n                "O - levels, GCSEs, or CSEs",\n                "A - levels",\n                "Further education e.g.City & Guilds / NVQs",\n                "University or Polytechnic degree",\n            ],\n        }\n    )\n    qualif.to_excel(excel_writer=tmp_path / "IXI.xls", sheet_name="Qualification_error")\n\n    with pytest.raises(\n        ValueError,\n        match=(\n            f"Qualification mapping is expected to be contained in a sheet called Qualification coming from the clinical data excel. "\n            f"Possibilities are supposed to be described in a QUALIFICATION column associated to keys from the \'ID\' column. "\n            f"In case the file downloaded from the IXI website changed format, please do not hesitate to report to us !"\n        ),\n    ):\n        _get_mapping(tmp_path, ClinicalDataMapping.QUALIFICATION)\n\n\ndef test_get_mapping_valueerror(tmp_path):\n    from clinica.converters.ixi_to_bids._utils import ClinicalDataMapping, _get_mapping\n\n    qualif = pd.DataFrame(\n        {\n            "ID": [1, 2, 3, 4, 5],\n            "QUALIFICATION_error": [\n                "No qualifications",\n                "O - levels, GCSEs, or CSEs",\n                "A - levels",\n                "Further education e.g.City & Guilds / NVQs",\n                "University or Polytechnic degree",\n            ],\n        }\n    )\n    qualif.to_excel(excel_writer=tmp_path / "IXI.xls", sheet_name="Qualification")\n\n    with pytest.raises(\n        ValueError,\n        match=(\n            f"Qualification mapping is expected to be contained in a sheet called Qualification coming from the clinical data excel. "\n            f"Possibilities are supposed to be described in a QUALIFICATION column associated to keys from the \'ID\' column. "\n            f"In case the file downloaded from the IXI website changed format, please do not hesitate to report to us !"\n        ),\n    ):\n        _get_mapping(tmp_path, ClinicalDataMapping.QUALIFICATION)\n\n\ndef test_write_json_image(tmp_path):\n    from clinica.converters.ixi_to_bids._utils import _write_json_image\n\n    _write_json_image(tmp_path / "test.json", hospital="Guys", field="1.5")\n    with open(tmp_path / "test.json", "r") as f:\n        data = json.load(f)\n\n    assert data["InstitutionName"] == "Guys"\n    assert data["MagneticFieldStrength (T)"] == "1.5"\n\n\ndef test_write_subject_no_dti(tmp_path):\n    from clinica.converters.ixi_to_bids._utils import _write_subject_no_dti\n\n    df = image_dataframe_builder(tmp_path)\n    bids_dir = tmp_path / "BIDS"\n    file_path = (\n        bids_dir\n        / f"sub-{df[\'subject\'][0]}"\n        / "ses-M000"\n        / "anat"\n        / f"sub-{df[\'subject\'][0]}_ses-M000_T1w"\n    )\n    _write_subject_no_dti(df, bids_dir)\n    json_files = list(bids_dir.rglob(f"sub-{df[\'subject\'][0]}*.json"))\n    nii_files = list(bids_dir.rglob(f"sub-{df[\'subject\'][0]}*.nii.gz"))\n\n    assert len(json_files) == 1 and json_files[0] == Path(f"{file_path}.json")\n    assert len(nii_files) == 1 and nii_files[0] == Path(f"{file_path}.nii.gz")\n\n\ndef test_write_subject_no_dti_empty(tmp_path):\n    from clinica.converters.ixi_to_bids._utils import _write_subject_no_dti\n\n    bids_dir = tmp_path / "BIDS"\n    bids_dir.mkdir()\n    _write_subject_no_dti(pd.DataFrame(), bids_dir)\n\n    assert not list(bids_dir.iterdir())\n\n\ndef test_find_subject_dti_data(tmp_path):\n    from clinica.converters.ixi_to_bids._utils import _find_subject_dti_data\n\n    (tmp_path / "IXI001-Guys-1234-T1.nii.gz").touch()\n    (tmp_path / "IXI001-Guys-1234-DTI").touch()\n    (tmp_path / "IXI001-Guys-DTI.nii.gz").touch()\n    tmp_image = tmp_path / "IXI001-Guys-1234-DTI-01.nii.gz"\n    tmp_image.touch()\n    list_dti = _find_subject_dti_data(data_directory=tmp_path, subject="IXI001")\n\n    assert len(list_dti) == 1 and list_dti[0] == tmp_image\n\n\ndef test_identify_expected_modalities(tmp_path):\n    from clinica.converters.ixi_to_bids._utils import _identify_expected_modalities\n\n    (tmp_path / "IXI-DTI").mkdir()\n    (tmp_path / "IXIdti").mkdir()\n    (tmp_path / "foo-bar").mkdir()\n\n    assert _identify_expected_modalities(tmp_path) == ["DTI"]\n\n\ndef test_write_scans_not_empty(tmp_path):\n    from clinica.converters.ixi_to_bids._utils import write_scans\n\n    (tmp_path / "sub-IXI001" / "ses-M000" / "anat").mkdir(parents=True)\n    (tmp_path / "sub-IXI001" / "ses-M000" / "anat" / "sub-IXI001_T1w.nii.gz").touch()\n    write_scans(tmp_path, participant="IXI001")\n    tsv_files = list(tmp_path.rglob("*.tsv"))\n    file_path = tmp_path / "sub-IXI001" / "ses-M000" / "sub-IXI001_ses-M000_scans.tsv"\n\n    assert len(tsv_files) == 1 and tsv_files[0] == file_path\n    assert (\n        assert_frame_equal(\n            pd.read_csv(file_path, sep="\\t"),\n            pd.DataFrame({"filename": ["anat/sub-IXI001_T1w.nii.gz"]}),\n        )\n        is None\n    )\n\n\ndef formatted_clinical_data_builder() -> pd.DataFrame:\n    return pd.DataFrame(\n        {\n            "source_id": ["IXI001"],\n            "participant_id": ["sub-IXI001"],\n            "session_id": ["ses-M000"],\n            "acq_time": ["2024-08-23"],\n            "sex": ["female"],\n            "ethnicity": ["Other"],\n            "marital status": ["Single"],\n            "occupation": ["Other"],\n            "qualification": ["A - levels"],\n            "date of birth": ["2000-01-01"],\n            "weight": [80],\n        }\n    )\n\n\ndef test_write_sessions(tmp_path):\n    from clinica.converters.ixi_to_bids._utils import write_sessions\n\n    clinical = formatted_clinical_data_builder()\n    (tmp_path / "sub-IXI001").mkdir()\n    write_sessions(tmp_path, clinical, "IXI001")\n    tsv_files = list(tmp_path.rglob("*.tsv"))\n    file_path = tmp_path / "sub-IXI001" / "sub-IXI001_sessions.tsv"\n\n    assert len(tsv_files) == 1 and tsv_files[0] == file_path\n    assert (\n        assert_frame_equal(\n            pd.read_csv(file_path, sep="\\t"),\n            clinical[["source_id", "session_id", "acq_time"]],\n        )\n        is None\n    )\n\n\ndef test_write_participants(tmp_path):\n    from clinica.converters.ixi_to_bids._utils import write_participants\n\n    clinical = formatted_clinical_data_builder()\n    expected = clinical.copy()\n    write_participants(tmp_path, clinical, ["IXI001", "IXI002"])\n    expected.drop(["acq_time", "session_id"], axis=1, inplace=True)\n    expected = pd.concat(\n        [expected, pd.DataFrame({col: ["n/a"] for col in expected.columns})]\n    ).reset_index(drop=True)\n    expected.loc[1, "source_id"] = "IXI002"\n    expected.loc[0, "weight"] = str(expected.loc[0, "weight"])\n    tsv_files = list(tmp_path.rglob("*.tsv"))\n\n    assert len(tsv_files) == 1 and tsv_files[0] == tmp_path / "participants.tsv"\n    assert (\n        assert_frame_equal(\n            pd.read_csv(tmp_path / "participants.tsv", sep="\\t", na_filter=False),\n            expected,\n        )\n        is None\n    )\n\n\n@patch("clinica.converters.ixi_to_bids._utils.cprint")\ndef test_check_modalities(mock_cprint, tmp_path):\n    from clinica.converters.ixi_to_bids._utils import check_modalities\n\n    (tmp_path / "IXI-DTI").mkdir()\n    (tmp_path / "IXI-DTI" / "IXI001-DTI-00.nii.gz").touch()\n    (tmp_path / "IXI-T1").mkdir()\n    (tmp_path / "IXI-T1" / "IXI001-T1.nii.gz").touch()\n    (tmp_path / "IXI-T1" / "IXI002-T1.nii.gz").touch()\n    (tmp_path / "IXIT1").mkdir()\n\n    message = (\n        f"Modalities : dti , T1w were identified inside {tmp_path} for conversion.\\n"\n        f"Some subjects do not have data for the following modalities :\\n"\n        f"IXI002 : dti\\n"\n    )\n\n    check_modalities(tmp_path, ["IXI001", "IXI002"])\n    mock_cprint.assert_called_once_with(message)\n',
        }
